mapper.select:
SELECT USER_ID, EMAIL, PASSWORD_RESET_TOKEN, PASSWORD_RESET_EXPIRY
FROM USERS
WHERE PASSWORD_RESET_TOKEN = #{token}

SELECT USER_ID, EMAIL, EMAIL_VERIFIED
FROM USERS
WHERE EMAIL_VERIFY_TOKEN = #{token}

mapper.update:
        UPDATE USERS
        SET LOGIN_FAIL_CNT = 0, ACCOUNT_LOCKED = 'N'
	WHERE EMAIL = #{_parameter}

UPDATE USERS
SET PASSWORD_RESET_TOKEN = #{passwordResetToken},
    PASSWORD_RESET_EXPIRY = #{passwordResetExpiry}
WHERE USER_ID = #{userId}

UPDATE USERS
SET EMAIL_VERIFIED = 'Y', EMAIL_VERIFY_TOKEN = NULL
WHERE EMAIL_VERIFY_TOKEN = #{token}

UPDATE USERS
SET EMAIL_VERIFY_TOKEN = #{emailVerifyToken}
WHERE USER_ID = #{userId}

UPDATE USERS
SET DELETED_AT = NOW(),
    DELETE_REASON = #{deleteReason}
WHERE USER_ID = #{userId}

UPDATE USERS
SET FORCE_PW_CHANGE = #{forcePwChange}
WHERE USER_ID = #{userId}
